/**
 * Returns true if `s` looks like a valid email address.
 *
 * Pragmatic validation, not full RFC 5322. Checks for a single "@",
 * a non-empty local part, and a domain with at least one dot and a
 * 2+ char TLD. No whitespace or consecutive dots allowed.
 */
function isValidEmail(s) {
  if (typeof s !== "string") return false;

  const email = s.trim();
  if (email.length === 0 || email.length > 254) return false;

  const re = /^[^\s@]+@[^\s@]+\.[^\s@]{2,}$/;
  if (!re.test(email)) return false;

  // Reject consecutive dots and leading/trailing dots in either part.
  const [local, domain] = email.split("@");
  if (/\.\./.test(email)) return false;
  if (local.startsWith(".") || local.endsWith(".")) return false;
  if (domain.startsWith(".") || domain.endsWith(".")) return false;

  return true;
}
```

Notes:
- Email validation has no perfect regex. The only ground truth is sending a confirmation message. This covers the common cases without rejecting valid-but-unusual addresses too aggressively.
- If you need stronger guarantees, validate format loosely (like above) then verify deliverability out-of-band.
