  const localOk = /^[A-Za-z0-9!#$%&'*+/=?^_`{|}~-]+(?:\.[A-Za-z0-9!#$%&'*+/=?^_`{|}~-]+)*$/.test(local);
  if (!localOk) return false;

  // Domain: dot-separated labels, each 1-63 chars, alphanumeric with internal hyphens; TLD >= 2 letters.
  const domainOk = /^(?:[A-Za-z0-9](?:[A-Za-z0-9-]{0,61}[A-Za-z0-9])?\.)+[A-Za-z]{2,}$/.test(domain);
  return domainOk;
